package ui.student;
import javax.swing.*;import javax.swing.table.*;import java.awt.*;import java.util.*;import controller.*;import dao.*;import model.*;import util.*;import ui.common.TableStyle;
public class InternshipSearchPanel extends JPanel{ JTextField field=UITheme.textField(),city=UITheme.textField(),duration=UITheme.textField(); JComboBox<String> type=new JComboBox<>(new String[]{"","Remote","On-site","Hybrid"}); JTable table=new JTable(); java.util.List<Internship> internships=new ArrayList<>(); public InternshipSearchPanel(){ setBackground(UITheme.BG); setLayout(new BorderLayout(10,10)); JPanel top=UITheme.panel(); top.setLayout(new GridLayout(2,5,8,8)); top.add(UITheme.label("Field"));top.add(UITheme.label("City"));top.add(UITheme.label("Type"));top.add(UITheme.label("Duration"));top.add(new JLabel()); top.add(field);top.add(city);top.add(type);top.add(duration); JButton search=UITheme.button("Search"); top.add(search); add(top,BorderLayout.NORTH); TableStyle.apply(table); add(new JScrollPane(table),BorderLayout.CENTER); JPanel bottom=UITheme.panel(); JButton apply=UITheme.button("Apply"); JButton save=UITheme.button("Bookmark"); JButton report=UITheme.button("Report Fake Internship"); bottom.add(apply);bottom.add(save);bottom.add(report); add(bottom,BorderLayout.SOUTH); search.addActionListener(e->load()); apply.addActionListener(e->apply()); save.addActionListener(e->bookmark()); report.addActionListener(e->report()); load(); } void load(){ internships=new InternshipController().search(field.getText(),city.getText(),type.getSelectedItem().toString(),duration.getText()); DefaultTableModel m=new DefaultTableModel(new Object[]{"ID","Title","Field","City","Type","Duration","Stipend","Deadline"},0); for(Internship j:internships)m.addRow(new Object[]{j.getId(),j.getTitle(),j.getField(),j.getCity(),j.getType(),j.getDuration(),j.getStipend(),j.getDeadline()}); table.setModel(m); TableStyle.apply(table);} int selectedJob(){ int r=table.getSelectedRow(); return r<0?0:Integer.parseInt(table.getValueAt(r,0).toString()); } int studentId(){ Student s=new StudentDAO().getByUserId(Session.getUserId()); return s==null?0:s.getId(); } void apply(){ int jid=selectedJob(); if(jid==0){DialogUtil.error(this,"Select a internship first.");return;} Resume res=new ResumeDAO().getLatestByStudent(studentId()); if(res==null){DialogUtil.error(this,"Please upload resume first.");return;} boolean ok=new ApplicationController().apply(new Application(0,jid,studentId(),res.getId(),Constants.APP_APPLIED,"Applied from portal",null)); DialogUtil.success(this,ok?"Application submitted":"Already applied or failed."); } void bookmark(){ int jid=selectedJob(); if(jid==0)return; DialogUtil.success(this,new BookmarkController().add(studentId(),jid)?"Internship bookmarked":"Already saved or failed");} void report(){ int jid=selectedJob(); if(jid==0)return; String reason=JOptionPane.showInputDialog(this,"Reason:"); if(reason!=null)new ReportController().add(Session.getUserId(),jid,reason); }}
